{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.12","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"gpu","dataSources":[{"sourceType":"datasetVersion","sourceId":78156,"datasetId":44109,"databundleVersionId":80619}],"dockerImageVersionId":31328,"isInternetEnabled":true,"language":"python","sourceType":"script","isGpuEnabled":true}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T08:44:07.849178Z\",\"iopub.execute_input\":\"2026-03-24T08:44:07.849401Z\",\"iopub.status.idle\":\"2026-03-24T08:44:45.512160Z\",\"shell.execute_reply.started\":\"2026-03-24T08:44:07.849376Z\",\"shell.execute_reply\":\"2026-03-24T08:44:45.511240Z\"}}\nimport os\nimport numpy as np\nfrom PIL import Image\n\n\ndef find_utkface_path(base=\"/kaggle/input\"):\n    for root, dirs, files in os.walk(base):\n        if any(f.endswith(\".jpg\") for f in files):\n            return root\n    return None\n\nimage_folder = find_utkface_path()\n\nif image_folder is None:\n    raise FileNotFoundError(\"Dataset introuvable\")\n\nprint(\"Dataset trouvé ici :\", image_folder)\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T08:44:59.935782Z\",\"iopub.execute_input\":\"2026-03-24T08:44:59.936647Z\",\"iopub.status.idle\":\"2026-03-24T08:48:39.783707Z\",\"shell.execute_reply.started\":\"2026-03-24T08:44:59.936612Z\",\"shell.execute_reply\":\"2026-03-24T08:48:39.782938Z\"}}\n# -------------------------------\n# Trouver automatiquement le dossier\n# -------------------------------\ndef find_utkface_path(base=\"/kaggle/input\"):\n    for root, dirs, files in os.walk(base):\n        if any(f.endswith(\".jpg\") for f in files):\n            return root\n    return None\n\nimage_folder = find_utkface_path()\n\nif image_folder is None:\n    raise FileNotFoundError(\"Dataset introuvable\")\n\nprint(\"Dataset trouvé ici :\", image_folder)\n\n# -------------------------------\n# Charger les images\n# -------------------------------\nimage_files = [f for f in os.listdir(image_folder) if f.endswith(\".jpg\")]\nprint(f\"Nombre de fichiers .jpg trouvés : {len(image_files)}\")\n\nimages = []\nlabels = []\n\nfor file in image_files:\n    try:\n        parts = file.split(\"_\")\n        age = int(parts[0])\n        gender = int(parts[1])\n\n        try:\n            race = int(parts[2])\n        except:\n            race = 4\n\n        img = Image.open(os.path.join(image_folder, file))\\\n                   .convert(\"L\")\\\n                   .resize((128, 128))\n\n        images.append(np.array(img))\n        labels.append([age, gender, race])\n\n    except:\n        continue\n\nimages = np.array(images)\nlabels = np.array(labels)\n\nprint(f\"Images chargées : {len(images)}\")\nprint(f\"Shape des images : {images.shape}\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:19:42.007242Z\",\"iopub.execute_input\":\"2026-03-24T10:19:42.007782Z\",\"iopub.status.idle\":\"2026-03-24T10:19:43.698748Z\",\"shell.execute_reply.started\":\"2026-03-24T10:19:42.007751Z\",\"shell.execute_reply\":\"2026-03-24T10:19:43.697978Z\"}}\n\"\"\"## 2. Imports et préparation des données\"\"\"\n\nimport tensorflow as tf\nfrom sklearn.model_selection import train_test_split\nfrom sklearn.metrics import classification_report, confusion_matrix, precision_recall_fscore_support, roc_auc_score, average_precision_score\nfrom sklearn.utils.class_weight import compute_class_weight\nfrom tensorflow.keras.utils import to_categorical\nfrom tensorflow.keras.layers import(\n    Input, Conv2D, SeparableConv2D, MaxPooling2D, Dense, Dropout,\n    BatchNormalization, GlobalAveragePooling2D, Flatten, Add, Multiply,\n    Reshape, Activation, RandomRotation, RandomZoom\n)\nfrom tensorflow.keras.models import Model\nfrom tensorflow.keras.optimizers import Adam\nfrom tensorflow.keras.regularizers import l2\nfrom tensorflow.keras.callbacks import EarlyStopping, ReduceLROnPlateau\nimport matplotlib.pyplot as plt\nimport seaborn as sns\n\nprint(f\"TensorFlow version : {tf.__version__}\")\nprint(f\"GPU disponible : {tf.config.list_physical_devices('GPU')}\")\n\n# -------------------------------\n# Données d'entrée\n# -------------------------------\nX = images.reshape(images.shape[0], 128, 128, 1)\nX = X.astype('float32') / 255.0\n\nprint(f\"Shape après reshape : {X.shape}\")\nprint(f\"X min/max : {X.min():.2f} / {X.max():.2f}\")\n\n# -------------------------------\n# Labels multi-tâches\n# -------------------------------\ny_age = labels[:, 0].astype(np.float32) / 100      # régression\ny_gender = labels[:, 1].astype(np.float32)    # binaire\ny_ethnicity = labels[:, 2].astype(np.int32)   # multi-classes\n\n# -------------------------------\n# 1) Train (70%) / Temp (30%)\n# -------------------------------\nX_train, X_temp, \\\ny_age_train, y_age_temp, \\\ny_gender_train, y_gender_temp, \\\ny_eth_train, y_eth_temp = train_test_split(\n    X,\n    y_age,\n    y_gender,\n    y_ethnicity,\n    test_size=0.3,\n    random_state=42,\n    stratify=y_ethnicity\n)\n\n# -------------------------------\n# 2) Validation (15%) / Test (15%)\n# -------------------------------\nX_val, X_test, \\\ny_age_val, y_age_test, \\\ny_gender_val, y_gender_test, \\\ny_eth_val, y_eth_test = train_test_split(\n    X_temp,\n    y_age_temp,\n    y_gender_temp,\n    y_eth_temp,\n    test_size=0.5,\n    random_state=42,\n    stratify=y_eth_temp\n)\n\n# -------------------------------\n# Création des versions tournées du test set\n# -------------------------------\nX_test_90  = np.rot90(X_test, k=1, axes=(1,2))\nX_test_180 = np.rot90(X_test, k=2, axes=(1,2))\nX_test_270 = np.rot90(X_test, k=3, axes=(1,2))\n\n# -------------------------------\n# Encodage ethnicité (softmax)\n# -------------------------------\ny_eth_train_cat = to_categorical(y_eth_train, num_classes=5)\ny_eth_test_cat = to_categorical(y_eth_test, num_classes=5)\n\ny_eth_val_cat   = to_categorical(y_eth_val, num_classes=5)   # MODIFICATION VERSION 7\n\n# -------------------------------\n# Class weights (ethnicité)\n# -------------------------------\nclass_weights = compute_class_weight(\n    class_weight='balanced',\n    classes=np.unique(y_eth_train),\n    y=y_eth_train\n)\nclass_weight_dict = dict(enumerate(class_weights))\nprint(f\"Class weights (ethnicité) : {class_weight_dict}\")\n\n# -------------------------------\n# Vérifications\n# -------------------------------\nprint(f\"X_train : {X_train.shape}\")\nprint(f\"X_test  : {X_test.shape}\")\nprint(f\"y_age_train : {y_age_train.shape}\")\nprint(f\"y_gender_train : {y_gender_train.shape}\")\nprint(f\"y_eth_train_cat : {y_eth_train_cat.shape}\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:19:48.184699Z\",\"iopub.execute_input\":\"2026-03-24T10:19:48.185041Z\",\"iopub.status.idle\":\"2026-03-24T10:19:48.201411Z\",\"shell.execute_reply.started\":\"2026-03-24T10:19:48.185012Z\",\"shell.execute_reply\":\"2026-03-24T10:19:48.200497Z\"}}\n###### AJOUT DE DATA AUGMENTATION POUR MODEL 5\nimport tensorflow as tf\nfrom tensorflow.keras import layers, models\n\ndef random_90_rotation(x):\n    k = tf.random.uniform([], 0, 4, dtype=tf.int32)\n    return tf.image.rot90(x, k)\n\n# data_augmentation = tf.keras.Sequential([\n#     layers.Lambda(random_90_rotation),\n#     layers.RandomRotation(0.5), # 0.1 vers 0.5 pour rotation de ± 180)\n#     layers.RandomZoom(0.1),\n#     layers.RandomTranslation(0.05, 0.05),\n# ])\n\ndata_augmentation = tf.keras.Sequential([\n    layers.RandomRotation(0.1),\n    layers.RandomZoom(0.05),\n    layers.RandomTranslation(0.02, 0.02),\n])\n\n#Créer un bloc de prétraitement des images qui va est intégré directement dans le modèle.\n#elle génère des versions légèrement modifiées des images pendant l’entraînement\n##Sequential => les opérations sont appliquées dans l’ordre\n##layers.RandomRotation(0.1) => rotation aléatoire (~ ±36°)\n##layers.RandomZoom(0.1), => zoom aléatoire\n## déplacement de l'image\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:20:08.778876Z\",\"iopub.execute_input\":\"2026-03-24T10:20:08.779427Z\",\"iopub.status.idle\":\"2026-03-24T10:20:08.924947Z\",\"shell.execute_reply.started\":\"2026-03-24T10:20:08.779396Z\",\"shell.execute_reply\":\"2026-03-24T10:20:08.924380Z\"}}\n# MODEL 6 / 7 --> Version 8\nfrom tensorflow.keras import layers, models\nfrom tensorflow.keras.optimizers import Adam\n\n# -------------------------------\n# Entrée\n# -------------------------------\ninput_img = layers.Input(shape=(128, 128, 1))\nx = data_augmentation(input_img)  ##MODIFICATION ICI POUR VERSION 7\n\n# -------------------------------\n# Bloc CNN 1\n# -------------------------------\nx = layers.Conv2D(32, (3,3), padding='same')(x)\nx = layers.BatchNormalization()(x)\nx = layers.ReLU()(x)\nx = layers.MaxPooling2D((2,2))(x)\n\n# -------------------------------\n# Bloc CNN 2\n# -------------------------------\nx = layers.Conv2D(64, (3,3), padding='same')(x)\nx = layers.BatchNormalization()(x)\nx = layers.ReLU()(x)\nx = layers.MaxPooling2D((2,2))(x)\n\n# -------------------------------\n# Bloc CNN 3\n# -------------------------------\nx = layers.Conv2D(128, (3,3), padding='same')(x)\nx = layers.BatchNormalization()(x)\nx = layers.ReLU()(x)\nx = layers.MaxPooling2D((2,2))(x)\n\n# -------------------------------\n# Bloc CNN 4 (profond)\n# -------------------------------\nx = layers.Conv2D(256, (3,3), padding='same')(x)\nx = layers.BatchNormalization()(x)\nx = layers.ReLU()(x)\n\n# -------------------------------\n# Global Pooling\n# -------------------------------\nx = layers.GlobalAveragePooling2D()(x)\n\n\n# -------------------------------\n# Features partagées\n# -------------------------------\nshared = layers.Dense(256, activation='relu')(x)\nshared = layers.BatchNormalization()(shared)\nshared = layers.Dropout(0.4)(shared)\n\n# ===============================\n# BRANCHE AGE (régression)\n# ===============================\nage_branch = Dense(128, activation='relu', kernel_regularizer=l2(1e-4))(shared)\nage_branch = Dropout(0.4)(age_branch)\n\nage_branch = Dense(64, activation='relu', kernel_regularizer=l2(1e-4))(age_branch)\nage_output = Dense(1, activation='linear', name='age')(age_branch)\n\n\n# ===============================\n# BRANCHE GENDER (classification simple)\n# ===============================\ngender_branch = layers.Dense(128, activation='relu')(shared)\ngender_branch = layers.Dropout(0.3)(gender_branch)\ngender_output = layers.Dense(1, activation='sigmoid', name='gender')(gender_branch)\n\n# ===============================\n# BRANCHE ETHNICITY (plus difficile → plus profond)\n# ===============================\neth_branch = layers.Dense(256, activation='relu')(shared)\neth_branch = layers.Dense(128, activation='relu')(eth_branch)\neth_branch = layers.Dropout(0.5)(eth_branch)\nethnicity_output = layers.Dense(5, activation='softmax', name='ethnicity')(eth_branch)\n\n\n\n\n# -------------------------------\n# Modèle final\n# -------------------------------\nmodel = models.Model(\n    inputs=input_img,\n    outputs=[age_output, gender_output, ethnicity_output]\n)\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:20:13.619242Z\",\"iopub.execute_input\":\"2026-03-24T10:20:13.619653Z\",\"iopub.status.idle\":\"2026-03-24T10:20:13.630222Z\",\"shell.execute_reply.started\":\"2026-03-24T10:20:13.619623Z\",\"shell.execute_reply\":\"2026-03-24T10:20:13.629224Z\"}}\nfrom tensorflow.keras.optimizers import Adam\n\nmodel.compile(\n    optimizer = tf.keras.optimizers.Adam(learning_rate=5e-5),\n    # optimizer = tf.keras.optimizers.Adam(learning_rate=1e-4),\n    # optimizer = tf.keras.optimizers.Adam(learning_rate=3e-5),\n    # optimizer=Adam(1e-4),\n    loss={\n        \"age\": tf.keras.losses.Huber(delta=8.0),\n        \"gender\": \"binary_crossentropy\",\n        \"ethnicity\": \"categorical_crossentropy\"\n    },\n    loss_weights = {\n    \"age\": 0.7,\n    \"gender\": 0.8,\n    \"ethnicity\": 1.0\n},\n    metrics={\n        \"age\": [\"mae\"],\n        \"gender\": [\"accuracy\"],\n        \"ethnicity\": [\"accuracy\"]\n    }\n)\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:20:16.396049Z\",\"iopub.execute_input\":\"2026-03-24T10:20:16.396834Z\",\"iopub.status.idle\":\"2026-03-24T10:20:16.401147Z\",\"shell.execute_reply.started\":\"2026-03-24T10:20:16.396803Z\",\"shell.execute_reply\":\"2026-03-24T10:20:16.400296Z\"}}\nfrom tensorflow.keras.callbacks import EarlyStopping, ReduceLROnPlateau\n\nearly_stop = EarlyStopping(\n    monitor='val_loss',\n    patience=12,              # arrête si ça n'améliore plus\n    restore_best_weights=True,\n    verbose=1\n)\n\nlr_scheduler = ReduceLROnPlateau(\n    monitor='val_loss',\n    factor=0.5,               # divise le LR\n    patience=5,               # après 4 epochs sans progrès\n    min_lr=1e-6,\n    verbose=1\n)\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:20:19.966960Z\",\"iopub.execute_input\":\"2026-03-24T10:20:19.967751Z\",\"iopub.status.idle\":\"2026-03-24T10:39:39.968405Z\",\"shell.execute_reply.started\":\"2026-03-24T10:20:19.967721Z\",\"shell.execute_reply\":\"2026-03-24T10:39:39.967748Z\"}}\nhistory = model.fit(\n    X_train,\n    {\n        'age': y_age_train,\n        'gender': y_gender_train,\n        'ethnicity': y_eth_train_cat\n    },\n    validation_data=(\n        X_val,  # utiliser X_val plutôt que X_test pour validation\n        {\n            'age': y_age_val,\n            'gender': y_gender_val,\n            'ethnicity': y_eth_val_cat\n        }\n    ),\n    epochs=80,\n    batch_size=128,\n    callbacks=[early_stop, lr_scheduler],  #AJOUTER APRES VERSION 7.1\n    shuffle=True\n)\n\nprint(\"\\n===== TEST ORIGINAL =====\")\nmodel.evaluate(X_test, {\n    'age': y_age_test,\n    'gender': y_gender_test,\n    'ethnicity': y_eth_test_cat\n})\n\nprint(\"\\n===== TEST 90° =====\")\nmodel.evaluate(X_test_90, {\n    'age': y_age_test,\n    'gender': y_gender_test,\n    'ethnicity': y_eth_test_cat\n})\n\nprint(\"\\n===== TEST 180° =====\")\nmodel.evaluate(X_test_180, {\n    'age': y_age_test,\n    'gender': y_gender_test,\n    'ethnicity': y_eth_test_cat\n})\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:39:58.055783Z\",\"iopub.execute_input\":\"2026-03-24T10:39:58.056577Z\",\"iopub.status.idle\":\"2026-03-24T10:39:58.191541Z\",\"shell.execute_reply.started\":\"2026-03-24T10:39:58.056545Z\",\"shell.execute_reply\":\"2026-03-24T10:39:58.190909Z\"}}\nimport matplotlib.pyplot as plt\n\nplt.figure(figsize=(6,4))\nplt.plot(history.history['loss'], label='Train loss')\nplt.plot(history.history['val_loss'], label='Validation loss')\nplt.xlabel('Epochs')\nplt.ylabel('Loss')\nplt.title('Loss globale du modèle multi-tâche')\nplt.legend()\nplt.show()\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:40:02.218077Z\",\"iopub.execute_input\":\"2026-03-24T10:40:02.218954Z\",\"iopub.status.idle\":\"2026-03-24T10:40:02.352820Z\",\"shell.execute_reply.started\":\"2026-03-24T10:40:02.218922Z\",\"shell.execute_reply\":\"2026-03-24T10:40:02.352286Z\"}}\nplt.figure(figsize=(6,4))\nplt.plot(history.history['age_mae'], label='Train MAE')\nplt.plot(history.history['val_age_mae'], label='Val MAE')\nplt.xlabel('Epochs')\nplt.ylabel('MAE')\nplt.title('MAE - Prédiction de l’âge')\nplt.legend()\nplt.show()\nplt.savefig(\"/kaggle/working/age_mae.png\")\nplt.close()\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:40:07.294668Z\",\"iopub.execute_input\":\"2026-03-24T10:40:07.295296Z\",\"iopub.status.idle\":\"2026-03-24T10:40:07.442854Z\",\"shell.execute_reply.started\":\"2026-03-24T10:40:07.295267Z\",\"shell.execute_reply\":\"2026-03-24T10:40:07.441930Z\"}}\nplt.figure(figsize=(6,4))\nplt.plot(history.history['gender_accuracy'], label='Train Acc')\nplt.plot(history.history['val_gender_accuracy'], label='Val Acc')\nplt.xlabel('Epochs')\nplt.ylabel('Accuracy')\nplt.title('Accuracy - Genre')\nplt.legend()\nplt.show()\n\nplt.savefig(\"/kaggle/working/gender_accuracy.png\")\nplt.close()\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-24T10:40:13.625371Z\",\"iopub.execute_input\":\"2026-03-24T10:40:13.626043Z\",\"iopub.status.idle\":\"2026-03-24T10:40:13.779472Z\",\"shell.execute_reply.started\":\"2026-03-24T10:40:13.625980Z\",\"shell.execute_reply\":\"2026-03-24T10:40:13.778637Z\"}}\nplt.figure(figsize=(6,4))\nplt.plot(history.history['ethnicity_accuracy'], label='Train Acc')\nplt.plot(history.history['val_ethnicity_accuracy'], label='Val Acc')\nplt.xlabel('Epochs')\nplt.ylabel('Accuracy')\nplt.title('Accuracy - Ethnicité')\nplt.legend()\nplt.show()\n\nplt.savefig(\"/kaggle/working/ethnicity_accuracy.png\")\nplt.close()\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-23T11:58:17.279593Z\",\"iopub.execute_input\":\"2026-03-23T11:58:17.279932Z\",\"iopub.status.idle\":\"2026-03-23T11:58:17.286825Z\",\"shell.execute_reply.started\":\"2026-03-23T11:58:17.279903Z\",\"shell.execute_reply\":\"2026-03-23T11:58:17.286132Z\"}}\n#Sauvegarder les métriques numériques (CSV → Output): metrics_training.csv\nimport pandas as pd\n\nmetrics_df = pd.DataFrame(history.history)\nmetrics_df.to_csv(\"/kaggle/working/metrics_training.csv\", index=False)\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-23T11:58:20.328148Z\",\"iopub.execute_input\":\"2026-03-23T11:58:20.329031Z\",\"iopub.status.idle\":\"2026-03-23T11:58:22.010369Z\",\"shell.execute_reply.started\":\"2026-03-23T11:58:20.329001Z\",\"shell.execute_reply\":\"2026-03-23T11:58:22.009732Z\"}}\n#Sauvegarder l’évaluation finale du modèle (TXT): test_metrics.txt\nresults = model.evaluate(\n    X_test,\n    {\n        'age': y_age_test,\n        'gender': y_gender_test,\n        'ethnicity': y_eth_test_cat\n    },\n    verbose=0\n)\n\nwith open(\"/kaggle/working/test_metrics.txt\", \"w\") as f:\n    for name, value in zip(model.metrics_names, results):\n        f.write(f\"{name}: {value:.4f}\\n\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-03-23T11:58:23.847504Z\",\"iopub.execute_input\":\"2026-03-23T11:58:23.848035Z\",\"iopub.status.idle\":\"2026-03-23T11:58:25.608803Z\",\"shell.execute_reply.started\":\"2026-03-23T11:58:23.848008Z\",\"shell.execute_reply\":\"2026-03-23T11:58:25.608040Z\"}}\nresults = model.evaluate(\n    X_test,\n    {\n        'age': y_age_test,\n        'gender': y_gender_test,\n        'ethnicity': y_eth_test_cat\n    },\n    verbose=1\n)\n\nfor name, value in zip(model.metrics_names, results):\n    print(f\"{name}: {value:.4f}\")","metadata":{"_uuid":"1d7ee90f-3e8c-402a-bddd-30beb3148d99","_cell_guid":"956e36ca-6d71-4252-b8a0-c4e63d48f8e2","trusted":true,"collapsed":false,"jupyter":{"outputs_hidden":false}},"outputs":[],"execution_count":null}]}